      node.text.trim match {
        case "" => None
        case txt if elementChildren.isEmpty => Some(ConfigSetting(currentPrefix.drop(1).mkString("."), txt))
        case _ => None
      }

    val childSettings =
      elementChildren.flatMap { child =>
        extractSettings(child, currentPrefix)
      }

    directText.toList ++ childSettings
  }
}

